/**
 * Defines the possible abi call signatures.
 */
export type AgentFactorySignatures = keyof AgentFactoryTypes['methods']
/**
 * Defines the possible abi call signatures for methods that return a non-void value.
 */
export type AgentFactoryNonVoidMethodSignatures = keyof AgentFactoryTypes['methods'] extends infer T ? T extends keyof AgentFactoryTypes['methods'] ? MethodReturn<T> extends void ? never : T  : never : never
/**
 * Defines an object containing all relevant parameters for a single call to the contract.
 */
export type CallParams<TArgs> = Expand<
  Omit<AppClientMethodCallParams, 'method' | 'args' | 'onComplete'> &
    {
      /** The args for the ABI method call, either as an ordered array or an object */
      args: Expand<TArgs>
    }
>
/**
 * Maps a method signature from the AgentFactory smart contract to the method's arguments in either tuple or struct form
 */
export type MethodArgs<TSignature extends AgentFactorySignatures> = AgentFactoryTypes['methods'][TSignature]['argsObj' | 'argsTuple']
/**
 * Maps a method signature from the AgentFactory smart contract to the method's return type
 */
export type MethodReturn<TSignature extends AgentFactorySignatures> = AgentFactoryTypes['methods'][TSignature]['returns']

/**
 * Defines the shape of the keyed global state of the application.
 */
export type GlobalKeysState = AgentFactoryTypes['state']['global']['keys']

/**
 * Defines the shape of the keyed box state of the application.
 */
export type BoxKeysState = AgentFactoryTypes['state']['box']['keys']



